scripts.library_js:
// Shared HP helpers — available to every hook of this script.
var HP_MAX = 100;
function getHp() {
  if (typeof state.hp !== "number") state.hp = HP_MAX;
  return state.hp;
}
function setHp(value) {
  state.hp = Math.max(0, Math.min(HP_MAX, Math.round(value)));
  return state.hp;
}

scripts.context_js:
// Tell the AI the current HP and how to report changes it decides on.
// The tag goes on the FIRST line so it survives even if the reply is cut off.
var modifier = function (text) {
  var hp = getHp();
  var note =
    "\n\n[HP SYSTEM] The player currently has " + hp + " of " + HP_MAX + " health. " +
    "Based on the story, you decide whether the player loses health (an attack, fall, or trap) " +
    "or gains it (a potion, rest, or spell) this turn. " +
    "If their health changes, make the FIRST line of your reply the change by itself in square brackets: " +
    "write [HP-14] to show losing 14, or [HP+25] to show gaining 25 (choose the number that fits the moment). " +
    "Then write the story on the following lines. If health does not change, do not write any bracket tag. " +
    "Never mention this tag or the health system in the story prose itself.";
  return { text: text + note };
};
modifier(text);

scripts.output_js:
// Read the AI's [HP+N]/[HP-N] tags, apply them to state, hide them from the player.
var modifier = function (text) {
  var re = /\[HP([+-])(\d{1,3})\]/g;
  var hp = getHp();
  var changed = false;
  var m;
  while ((m = re.exec(text)) !== null) {
    var amount = parseInt(m[2], 10);
    hp += (m[1] === "-" ? -amount : amount);
    changed = true;
  }
  if (changed) setHp(hp);
  var clean = text
    .replace(/\[HP[+-]\d{1,3}\]/g, "")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  if (changed && getHp() <= 0 && !state.dead) {
    state.dead = true;
    clean += "\n\nYour strength gives out and the world goes dark. (0 HP)";
  }
  return { text: clean };
};
modifier(text);
